def verify_message_signature(payload_dict: dict, signature: str) -> bool:
    """Verify HMAC signature to ensure message integrity and authenticity."""
    signing_key = os.environ.get("MESSAGE_SIGNING_KEY")
    if not signing_key:
        logging.error("MESSAGE_SIGNING_KEY not configured")
