def create_signed_job_message(
    job_id: str,
    job_type: str,
    parameters: Dict[str, Any],
) -> str:
    """Create a signed JSON message for submitting to the queue."""
    signing_key = os.environ.get("MESSAGE_SIGNING_KEY")

    payload = {
        "job_id": job_id,
        "job_type": job_type,
        "parameters": parameters,
        "created_at": time.time(),
    }

    if signing_key:
        canonical = json.dumps(payload, sort_keys=True, separators=(",", ":"))
        signature = hmac.new(
            signing_key.encode("utf-8"),
            canonical.encode("utf-8"),
            hashlib.sha256,
        ).hexdigest()
        payload["signature"] = signature

    return json.dumps(payload)